use crate::models::{Command, Report, CommandStatus};
use anyhow::Result;

pub fn render_index(commands: &[Command], report: &Report) -> Result<String> {
    let mut groups = std::collections::HashSet::new();
    for cmd in commands {
        if let Some(ref cmd_groups) = cmd.groups {
            for group in cmd_groups {
                groups.insert(group.clone());
            }
        }
    }
    let mut groups: Vec<_> = groups.into_iter().collect();
    groups.sort();

    // Build command data JSON safely
    let command_jsons: Vec<String> = commands
        .iter()
        .map(|cmd| {
            let status = cmd.status(report);
            let groups_json = cmd.groups.as_ref()
                .map(|g| format!("[{}]", g.iter().map(|s| format!("\"{}\"", escape_json(s))).collect::<Vec<_>>().join(",")))
                .unwrap_or_else(|| "[]".to_string());
            
            format!(
                "{{\"name\":\"{}\",\"desc\":\"{}\",\"groups\":{},\"status\":\"{}\"}}",
                escape_json(&cmd.name),
                escape_json(&cmd.short_description()),
                groups_json,
                status.as_str()
            )
        })
        .collect();
    let command_data = command_jsons.join(",");

    let mut groups_options = String::new();
    for group in groups {
        groups_options.push_str(&format!("<option value=\"{}\">{}</option>\n", escape_html(&group), escape_html(&group)));
    }

    let total_commands = commands.len();
    
    let mut html = String::new();
    html.push_str("<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>HEMTT Wiki - Arma 3 Command Reference</title>\n    <link rel=\"stylesheet\" href=\"css/styles.css\">\n</head>\n<body class=\"bg-gray-50\">\n    <div class=\"min-h-screen\">\n        <!-- Header -->\n        <header class=\"bg-gradient-to-r from-blue-600 to-blue-800 text-white shadow-lg\">\n            <div class=\"max-w-7xl mx-auto px-4 py-8\">\n                <h1 class=\"text-4xl font-bold\">HEMTT Wiki</h1>\n                <p class=\"text-blue-100 mt-2\">Arma 3 Command Reference Parser</p>\n                <p class=\"text-sm text-blue-200 mt-1\">Comprehensive command viewer with filtering and search capabilities</p>\n            </div>\n        </header>\n\n        <!-- Main Content -->\n        <main class=\"max-w-7xl mx-auto px-4 py-8\">\n            <!-- Filters Section -->\n            <div class=\"bg-white rounded-lg shadow-md p-6 mb-8\">\n                <h2 class=\"text-2xl font-bold text-gray-800 mb-6\">Search & Filter</h2>\n                \n                <div class=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-6\">\n                    <!-- Search Box -->\n                    <div>\n                        <label for=\"search\" class=\"block text-sm font-medium text-gray-700 mb-2\">Search Commands</label>\n                        <input type=\"text\" id=\"search\" placeholder=\"Enter command name...\" class=\"w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500\">\n                    </div>\n\n                    <!-- Status Filter -->\n                    <div>\n                        <label for=\"status\" class=\"block text-sm font-medium text-gray-700 mb-2\">Status</label>\n                        <select id=\"status\" class=\"w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500\">\n                            <option value=\"\">All Status</option>\n                            <option value=\"Passed\">Passed</option>\n                            <option value=\"Failed\">Failed</option>\n                            <option value=\"Outdated\">Outdated</option>\n                        </select>\n                    </div>\n\n                    <!-- Group Filter -->\n                    <div>\n                        <label for=\"group\" class=\"block text-sm font-medium text-gray-700 mb-2\">Group</label>\n                        <select id=\"group\" class=\"w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500\">\n                            <option value=\"\">All Groups</option>\n");
    html.push_str(&groups_options);
    html.push_str("                        </select>\n                    </div>\n\n                    <!-- Sort -->\n                    <div>\n                        <label for=\"sort\" class=\"block text-sm font-medium text-gray-700 mb-2\">Sort By</label>\n                        <select id=\"sort\" class=\"w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500\">\n                            <option value=\"name\">Name (A-Z)</option>\n                            <option value=\"name-desc\">Name (Z-A)</option>\n                            <option value=\"status\">Status</option>\n                            <option value=\"group\">Group</option>\n                        </select>\n                    </div>\n                </div>\n\n                <!-- Results Count -->\n                <div class=\"text-sm text-gray-600\">\n                    Showing <span id=\"result-count\">0</span> of <span id=\"total-count\"></span> commands\n                </div>\n            </div>\n\n            <!-- Commands Grid -->\n            <div id=\"commands-container\" class=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6\">\n                <!-- Commands will be loaded here -->\n                <div class=\"col-span-full text-center py-12\">\n                    <p class=\"text-gray-500\">Loading commands...</p>\n                </div>\n            </div>\n        </main>\n\n        <!-- Footer -->\n        <footer class=\"bg-gray-800 text-gray-300 mt-16 py-8\">\n            <div class=\"max-w-7xl mx-auto px-4\">\n                <div class=\"flex justify-between items-center\">\n                    <div>\n                        <p class=\"font-semibold\">HEMTT Wiki</p>\n                        <p class=\"text-sm\">Arma 3 Command Reference Parser</p>\n                    </div>\n                    <div class=\"text-sm\">\n                        <p>Last updated: <span id=\"last-updated\">--</span></p>\n                    </div>\n                </div>\n            </div>\n        </footer>\n    </div>\n\n    <script>\n        const allCommands = [");
    html.push_str(&command_data);
    html.push_str("];\n        let filteredCommands = [];\n        const filterState = {search: '', status: '', group: '', sort: 'name'};\n        const today = new Date();\n        document.getElementById('last-updated').textContent = today.toLocaleDateString();\n        document.getElementById('total-count').textContent = allCommands.length;\n        const searchInput = document.getElementById('search');\n        const statusSelect = document.getElementById('status');\n        const groupSelect = document.getElementById('group');\n        const sortSelect = document.getElementById('sort');\n        searchInput.addEventListener('input', (e) => {filterState.search = e.target.value.toLowerCase(); applyFilters();});\n        statusSelect.addEventListener('change', (e) => {filterState.status = e.target.value; applyFilters();});\n        groupSelect.addEventListener('change', (e) => {filterState.group = e.target.value; applyFilters();});\n        sortSelect.addEventListener('change', (e) => {filterState.sort = e.target.value; applyFilters();});\n        function applyFilters() {\n            filteredCommands = allCommands.filter(cmd => {\n                if (filterState.search && !cmd.name.toLowerCase().includes(filterState.search)) return false;\n                if (filterState.status && cmd.status !== filterState.status) return false;\n                if (filterState.group && (!cmd.groups || !cmd.groups.includes(filterState.group))) return false;\n                return true;\n            });\n            switch (filterState.sort) {\n                case 'name': filteredCommands.sort((a, b) => a.name.localeCompare(b.name)); break;\n                case 'name-desc': filteredCommands.sort((a, b) => b.name.localeCompare(a.name)); break;\n                case 'status': {const statusOrder = {'Passed': 0, 'Outdated': 1, 'Failed': 2, 'Unknown': 3}; filteredCommands.sort((a, b) => (statusOrder[a.status] || 3) - (statusOrder[b.status] || 3));} break;\n                case 'group': filteredCommands.sort((a, b) => (a.groups?.[0] || 'Z').localeCompare(b.groups?.[0] || 'Z')); break;\n            }\n            updateCounts();\n            renderCommands();\n        }\n        function updateCounts() {document.getElementById('result-count').textContent = filteredCommands.length;}\n        function renderCommands() {\n            const container = document.getElementById('commands-container');\n            if (filteredCommands.length === 0) {\n                container.innerHTML = '<div class=\"col-span-full text-center py-12\"><p class=\"text-gray-500\">No commands found matching your filters.</p></div>';\n                return;\n            }\n            container.innerHTML = filteredCommands.map(cmd => {\n                const statusClass = {'Passed': 'status-passed', 'Failed': 'status-failed', 'Outdated': 'status-outdated', 'Unknown': 'status-unknown'}[cmd.status] || 'status-unknown';\n                const groups = cmd.groups ? cmd.groups.map(g => `<span class=\"group-tag\">${escapeHtml(g)}</span>`).join('') : '';\n                return `<div class=\"command-card bg-white rounded-lg shadow-md overflow-hidden\"><div class=\"p-6\"><div class=\"flex items-start justify-between mb-3\"><h3 class=\"text-xl font-bold text-gray-800 break-words flex-1\">${escapeHtml(cmd.name)}</h3><span class=\"${statusClass} px-3 py-1 rounded text-xs font-semibold ml-2 flex-shrink-0\">${cmd.status}</span></div><p class=\"text-gray-600 text-sm mb-4\">${escapeHtml(cmd.desc || 'No description')}</p>${groups ? `<div class=\"mb-4\">${groups}</div>` : ''}</div></div>`;\n            }).join('');\n        }\n        function escapeHtml(text) {\n            if (!text) return '';\n            const div = document.createElement('div');\n            div.textContent = text;\n            return div.innerHTML;\n        }\n        applyFilters();\n    </script>\n</body>\n</html>");

    let html = html;

    Ok(html)
}

